import { EntitySchema } from "typeorm";

export type ConversationChannel = "dashboard" | "telegram" | "whatsapp";
export type ConversationTerminationReason =
  | "model_final"
  | "max_turns"
  | "token_cap"
  | "points_budget_exhausted"
  | "user_cancelled"
  | "error";

export interface ConversationEntity {
  id: string;
  userId: string;
  channel: ConversationChannel;
  startedAt: Date;
  endedAt: Date | null;
  turnCount: number;
  totalTokensIn: number;
  totalTokensOut: number;
  totalCostUsd: string;
  terminationReason: ConversationTerminationReason | null;
  toolCallCount: number;
  model: string | null;
}

export const ConversationEntitySchema = new EntitySchema<ConversationEntity>({
  name: "Conversation",
  tableName: "conversations",
  columns: {
    id: { type: "varchar", length: 64, primary: true },
    userId: { name: "user_id", type: "varchar", length: 64 },
    channel: { type: "varchar", length: 16 },
    startedAt: { name: "started_at", type: "timestamptz" },
    endedAt: { name: "ended_at", type: "timestamptz", nullable: true },
    turnCount: { name: "turn_count", type: "integer", default: 0 },
    totalTokensIn: { name: "total_tokens_in", type: "integer", default: 0 },
    totalTokensOut: { name: "total_tokens_out", type: "integer", default: 0 },
    totalCostUsd: { name: "total_cost_usd", type: "numeric", precision: 14, scale: 6 },
    terminationReason: { name: "termination_reason", type: "varchar", length: 32, nullable: true },
    toolCallCount: { name: "tool_call_count", type: "integer", default: 0 },
    model: { type: "varchar", length: 255, nullable: true },
  },
});

import type { DataSource } from "typeorm";
import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";
import { logger } from "./logger.js";

/**
 * Feature flag service — reads / writes / seeds rows in `feature_flags`.
 *
 * Spec: design.md §4.15. Phase 1 task 1.2.
 *
 * Two row shapes:
 *   • boolean toggle: `enabled` is the value, `value_json` is null
 *   • configured value: `value_json` holds the value, `enabled` is true if the
 *     value is "active" (always true for value rows; per-user disable can be
 *     expressed by inserting a scoped row with `enabled = false`)
 *
 * Resolution order: per-user scoped row → global row → built-in default.
 */

// -----------------------------------------------------------------------------
// Default flag set (Phase 1; per tasks.md 1.2 and design §3 row 7).
// -----------------------------------------------------------------------------

interface BooleanFlagDefault {
  kind: "boolean";
  name: string;
  enabled: boolean;
}
interface ValueFlagDefault {
  kind: "value";
  name: string;
  value: unknown;
}
type FlagDefault = BooleanFlagDefault | ValueFlagDefault;

const DEFAULT_FLAGS: readonly FlagDefault[] = [
  // Phase-gated rollout switches. All defaults match the as-deployed state at
  // start of Phase 1: only the legacy job runners and the self-correcting retry
  // are on; everything else lights up as later phases ship.
  { kind: "boolean", name: "chat_agent_enabled", enabled: false },
  { kind: "boolean", name: "output_filter_enabled", enabled: false },
  { kind: "boolean", name: "structured_outputs_enabled", enabled: false },
  { kind: "boolean", name: "self_correcting_retry_enabled", enabled: true },
  { kind: "boolean", name: "asset_class_dispatch_enabled", enabled: false },
  { kind: "boolean", name: "transactions_ledger_enabled", enabled: false },
  { kind: "boolean", name: "snooze_enabled", enabled: false },
  { kind: "boolean", name: "legacy_job_runners_enabled", enabled: true },

  // Admin-configurable scalar values (defaults from design §3 row 7).
  { kind: "value", name: "max_turns", value: 12 },
  { kind: "value", name: "conversation_token_cap", value: 120000 },
  { kind: "value", name: "search_web_max_results", value: 8 },
  { kind: "value", name: "max_wait_for_job_sec", value: 600 },
  { kind: "value", name: "max_snooze_days", value: 180 },

  // List-shaped configuration. Empty by default — startup guards in Phase 5/8
  // will refuse to start the relevant subsystem with empty values when their
  // feature flag is enabled, so an empty list cannot silently allow access.
  { kind: "value", name: "forbidden_pattern_list", value: [
    // File paths
    "~/clawd/", "users/", ".openclaw", "data/triggers/", "node_modules/",
    // Internal terms
    "step queue", "openclaw", "watchdog", "userIsolation", "workspace", "clawd",
    // Model name prefixes (prevent leaking which model is in use)
    "claude-", "gpt-", "gemini-", "deepseek-", "o1-", "o3-",
  ] },
  { kind: "value", name: "cors_allow_list", value: [] },
  { kind: "value", name: "persona_redirect_line", value:
    "I can help with portfolio analysis, strategies, verdicts, and the actions I have tools for. What would you like to work on?" },

  // Daily-brief coverage limit (N3 — replaces the fake `pro` plan check). The
  // initial value mirrors the legacy hardcoded constant; admin can tune at
  // runtime once the dashboard exposes it.
  { kind: "value", name: "coverage_limit", value: 10 },
];

// -----------------------------------------------------------------------------
// Reader helpers
// -----------------------------------------------------------------------------

interface FeatureFlagRow {
  flag_name: string;
  scope_user_id: string | null;
  enabled: boolean;
  value_json: unknown;
  updated_by: string;
  updated_at: Date;
}

async function readScopedRow(
  ds: DataSource,
  flagName: string,
  userId: string | null
): Promise<FeatureFlagRow | null> {
  if (userId === null) {
    const rows = await ds.query<FeatureFlagRow[]>(
      `SELECT flag_name, scope_user_id, enabled, value_json, updated_by, updated_at
         FROM feature_flags
        WHERE flag_name = $1 AND scope_user_id IS NULL
        LIMIT 1`,
      [flagName]
    );
    return rows[0] ?? null;
  }
  const rows = await ds.query<FeatureFlagRow[]>(
    `SELECT flag_name, scope_user_id, enabled, value_json, updated_by, updated_at
       FROM feature_flags
      WHERE flag_name = $1 AND scope_user_id = $2
      LIMIT 1`,
    [flagName, userId]
  );
  return rows[0] ?? null;
}

function defaultFor(name: string): FlagDefault | undefined {
  return DEFAULT_FLAGS.find((flag) => flag.name === name);
}

// -----------------------------------------------------------------------------
// Public API
// -----------------------------------------------------------------------------

/**
 * Resolve a boolean toggle flag. Returns the per-user row first, then the
 * global row, then the built-in default. Returns `false` if the DB is not
 * configured AND there is no built-in default for the name.
 */
export async function isFeatureEnabled(name: string, userId?: string): Promise<boolean> {
  const builtIn = defaultFor(name);
  const fallback = builtIn?.kind === "boolean" ? builtIn.enabled : false;

  if (!isApplicationDatabaseConfigured()) return fallback;

  try {
    const ds = await getApplicationDataSource();
    if (userId) {
      const scoped = await readScopedRow(ds, name, userId);
      if (scoped) return scoped.enabled;
    }
    const global = await readScopedRow(ds, name, null);
    if (global) return global.enabled;
    return fallback;
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    logger.warn(`feature_flag_read_failed name=${name} error=${message}`);
    return fallback;
  }
}

/**
 * Resolve a value-shaped flag. Generic so callers can declare the expected
 * shape; the DB cannot enforce shape, so the caller is responsible for
 * defensive parsing of the result.
 */
export async function getFeatureValue<T>(name: string, userId?: string): Promise<T | undefined> {
  const builtIn = defaultFor(name);
  const fallback = builtIn?.kind === "value" ? (builtIn.value as T) : undefined;

  if (!isApplicationDatabaseConfigured()) return fallback;

  try {
    const ds = await getApplicationDataSource();
    if (userId) {
      const scoped = await readScopedRow(ds, name, userId);
      if (scoped && scoped.value_json !== null && scoped.value_json !== undefined) {
        return scoped.value_json as T;
      }
    }
    const global = await readScopedRow(ds, name, null);
    if (global && global.value_json !== null && global.value_json !== undefined) {
      return global.value_json as T;
    }
    return fallback;
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    logger.warn(`feature_flag_value_read_failed name=${name} error=${message}`);
    return fallback;
  }
}

export interface SetFeatureFlagInput {
  name: string;
  scopeUserId: string | null;
  enabled: boolean;
  valueJson?: unknown;
  updatedBy: string;
}

/**
 * Upsert a flag row. Used by the admin endpoint and by migration scripts.
 * Each toggle MUST also write an admin_audit_log row (P3.2); that audit row
 * is written by the caller, not by this function, so this stays a pure
 * data-layer helper.
 */
export async function setFeatureFlag(input: SetFeatureFlagInput): Promise<void> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("setFeatureFlag requires the application database to be configured");
  }
  const ds = await getApplicationDataSource();
  const valueJson = input.valueJson === undefined ? null : input.valueJson;

  if (input.scopeUserId === null) {
    // Global row. Use the partial unique index on flag_name WHERE scope_user_id IS NULL.
    const existing = await readScopedRow(ds, input.name, null);
    if (existing) {
      await ds.query(
        `UPDATE feature_flags
            SET enabled = $1,
                value_json = $2::jsonb,
                updated_at = NOW(),
                updated_by = $3
          WHERE flag_name = $4 AND scope_user_id IS NULL`,
        [input.enabled, valueJson === null ? null : JSON.stringify(valueJson), input.updatedBy, input.name]
      );
    } else {
      await ds.query(
        `INSERT INTO feature_flags (flag_name, scope_user_id, enabled, value_json, updated_at, updated_by)
         VALUES ($1, NULL, $2, $3::jsonb, NOW(), $4)`,
        [input.name, input.enabled, valueJson === null ? null : JSON.stringify(valueJson), input.updatedBy]
      );
    }
    return;
  }

  // Scoped row.
  const existing = await readScopedRow(ds, input.name, input.scopeUserId);
  if (existing) {
    await ds.query(
      `UPDATE feature_flags
          SET enabled = $1,
              value_json = $2::jsonb,
              updated_at = NOW(),
              updated_by = $3
        WHERE flag_name = $4 AND scope_user_id = $5`,
      [
        input.enabled,
        valueJson === null ? null : JSON.stringify(valueJson),
        input.updatedBy,
        input.name,
        input.scopeUserId,
      ]
    );
  } else {
    await ds.query(
      `INSERT INTO feature_flags (flag_name, scope_user_id, enabled, value_json, updated_at, updated_by)
       VALUES ($1, $2, $3, $4::jsonb, NOW(), $5)`,
      [
        input.name,
        input.scopeUserId,
        input.enabled,
        valueJson === null ? null : JSON.stringify(valueJson),
        input.updatedBy,
      ]
    );
  }
}

/**
 * Seed the default flag set on startup. Idempotent: existing rows are not
 * modified, so an admin override survives every restart. New names added in
 * later phases are inserted on the next boot.
 */
export async function ensureDefaultFeatureFlags(ds: DataSource): Promise<void> {
  for (const flag of DEFAULT_FLAGS) {
    const enabled = flag.kind === "boolean" ? flag.enabled : true;
    const valueJson = flag.kind === "value" ? JSON.stringify(flag.value) : null;
    await ds.query(
      `INSERT INTO feature_flags (flag_name, scope_user_id, enabled, value_json, updated_at, updated_by)
       SELECT $1::VARCHAR, NULL, $2::BOOLEAN, $3::jsonb, NOW(), 'system_default'
        WHERE NOT EXISTS (
          SELECT 1 FROM feature_flags
           WHERE flag_name = $1::VARCHAR AND scope_user_id IS NULL
        )`,
      [flag.name, enabled, valueJson]
    );
  }
}

/** Test-only helper: wipe all rows. Not exported from the package surface. */
export async function _resetFeatureFlagsForTest(): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(`DELETE FROM feature_flags`);
}

// Names of flags this module knows about — exported for type-narrow callers.
export const KNOWN_BOOLEAN_FLAGS = DEFAULT_FLAGS
  .filter((flag): flag is BooleanFlagDefault => flag.kind === "boolean")
  .map((flag) => flag.name);

export const KNOWN_VALUE_FLAGS = DEFAULT_FLAGS
  .filter((flag): flag is ValueFlagDefault => flag.kind === "value")
  .map((flag) => flag.name);

import { randomUUID } from "crypto";
import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../../db/applicationDataSource.js";
import type { ConversationChannel, ConversationTerminationReason } from "../../db/entities/ConversationEntity.js";
import type { TurnRole } from "../../db/entities/ConversationTurnEntity.js";
import { unwrapMutationRows } from "../dbUtils.js";

/**
 * Conversation store — Phase 5, task 5.8.
 *
 * Spec: design.md §4.11; C2.1, C2.2, C2.3, NFR6.2, NFR6.4.
 *
 * Persists every conversation turn, tool call, and conversation summary.
 * `appendToolCall` writes the audit row BEFORE the handler executes (NFR6.4).
 */

export interface ConversationRecord {
  id: string;
  userId: string;
  channel: ConversationChannel;
  startedAt: string;
  endedAt: string | null;
  turnCount: number;
  totalTokensIn: number;
  totalTokensOut: number;
  totalCostUsd: number;
  terminationReason: ConversationTerminationReason | null;
  toolCallCount: number;
  model: string | null;
}

export interface TurnRecord {
  conversationId: string;
  turnIndex: number;
  role: TurnRole;
  content: unknown;
  model: string | null;
  tokensIn: number;
  tokensOut: number;
  costUsd: number;
  latencyMs: number;
  createdAt: string;
}

export interface AppendTurnInput {
  role: TurnRole;
  content: unknown;
  model?: string | null;
  tokensIn?: number;
  tokensOut?: number;
  costUsd?: number;
  latencyMs?: number;
}

// ---------------------------------------------------------------------------
// Create / load
// ---------------------------------------------------------------------------

export async function createConversation(input: {
  userId: string;
  channel: ConversationChannel;
  model?: string | null;
}): Promise<ConversationRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("createConversation requires the application database");
  }
  const ds = await getApplicationDataSource();
  const id = `conv_${Date.now()}_${randomUUID().slice(0, 8)}`;
  const rows = await ds.query(
    `INSERT INTO conversations
       (id, user_id, channel, started_at, turn_count, total_tokens_in, total_tokens_out,
        total_cost_usd, tool_call_count, model)
     VALUES ($1, $2, $3, NOW(), 0, 0, 0, 0, 0, $4)
     RETURNING id, user_id, channel, started_at, ended_at, turn_count,
               total_tokens_in, total_tokens_out, total_cost_usd,
               termination_reason, tool_call_count, model`,
    [id, input.userId, input.channel, input.model ?? null]
  ) as Array<Record<string, unknown>>;
  return fromRow(rows[0]!);
}

export async function loadConversation(conversationId: string): Promise<ConversationRecord | null> {
  if (!isApplicationDatabaseConfigured()) return null;
  const ds = await getApplicationDataSource();
  const rows = await ds.query(
    `SELECT id, user_id, channel, started_at, ended_at, turn_count,
            total_tokens_in, total_tokens_out, total_cost_usd,
            termination_reason, tool_call_count, model
       FROM conversations WHERE id = $1 LIMIT 1`,
    [conversationId]
  ) as Array<Record<string, unknown>>;
  return rows[0] ? fromRow(rows[0]) : null;
}

// ---------------------------------------------------------------------------
// Turn management
// ---------------------------------------------------------------------------

export async function appendTurn(
  conversationId: string,
  input: AppendTurnInput
): Promise<TurnRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("appendTurn requires the application database");
  }
  const ds = await getApplicationDataSource();

  return ds.transaction(async (manager) => {
    // Increment turn_count and get the new index atomically.
    // unwrapMutationRows handles TypeORM's [rows, rowCount] UPDATE RETURNING shape.
    const rawUpdated = await manager.query(
      `UPDATE conversations
          SET turn_count = turn_count + 1,
              total_tokens_in = total_tokens_in + $2,
              total_tokens_out = total_tokens_out + $3,
              total_cost_usd = total_cost_usd + $4
        WHERE id = $1
        RETURNING turn_count`,
      [
        conversationId,
        input.tokensIn ?? 0,
        input.tokensOut ?? 0,
        input.costUsd ?? 0,
      ]
    );
    const updatedRows = unwrapMutationRows<{ turn_count: number }>(rawUpdated);
    if (updatedRows.length === 0) {
      throw new Error(`conversation_not_found: ${conversationId}`);
    }
    const turnIndex = updatedRows[0]!.turn_count - 1;

    const rows = await manager.query(
      `INSERT INTO conversation_turns
         (conversation_id, turn_index, role, content, model,
          tokens_in, tokens_out, cost_usd, latency_ms, created_at)
       VALUES ($1, $2, $3, $4::jsonb, $5, $6, $7, $8, $9, NOW())
       RETURNING conversation_id, turn_index, role, content, model,
                 tokens_in, tokens_out, cost_usd, latency_ms, created_at`,
      [
        conversationId,
        turnIndex,
        input.role,
        JSON.stringify(input.content),
        input.model ?? null,
        input.tokensIn ?? 0,
        input.tokensOut ?? 0,
        input.costUsd ?? 0,
        input.latencyMs ?? 0,
      ]
    ) as Array<Record<string, unknown>>;
    return fromTurnRow(rows[0]!);
  });
}

export async function loadHistory(
  conversationId: string,
  maxTurns = 50
): Promise<TurnRecord[]> {
  if (!isApplicationDatabaseConfigured()) return [];
  const ds = await getApplicationDataSource();
  const rows = await ds.query(
    `SELECT conversation_id, turn_index, role, content, model,
            tokens_in, tokens_out, cost_usd, latency_ms, created_at
       FROM conversation_turns
      WHERE conversation_id = $1
      ORDER BY turn_index ASC
      LIMIT $2`,
    [conversationId, maxTurns]
  ) as Array<Record<string, unknown>>;
  return rows.map(fromTurnRow);
}

// ---------------------------------------------------------------------------
// Finalization
// ---------------------------------------------------------------------------

export async function endConversation(
  conversationId: string,
  reason: ConversationTerminationReason,
  model?: string | null
): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE conversations
        SET ended_at = NOW(),
            termination_reason = $2,
            model = COALESCE($3, model)
      WHERE id = $1`,
    [conversationId, reason, model ?? null]
  );
}

export async function incrementToolCallCount(conversationId: string): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE conversations SET tool_call_count = tool_call_count + 1 WHERE id = $1`,
    [conversationId]
  );
}

// ---------------------------------------------------------------------------
// Row mappers
// ---------------------------------------------------------------------------

function fromRow(row: Record<string, unknown>): ConversationRecord {
  return {
    id: String(row["id"]),
    userId: String(row["user_id"]),
    channel: String(row["channel"]) as ConversationChannel,
    startedAt: toIso(row["started_at"]),
    endedAt: row["ended_at"] ? toIso(row["ended_at"]) : null,
    turnCount: Number(row["turn_count"] ?? 0),
    totalTokensIn: Number(row["total_tokens_in"] ?? 0),
    totalTokensOut: Number(row["total_tokens_out"] ?? 0),
    totalCostUsd: Number(row["total_cost_usd"] ?? 0),
    terminationReason: (row["termination_reason"] as ConversationTerminationReason | null) ?? null,
    toolCallCount: Number(row["tool_call_count"] ?? 0),
    model: row["model"] ? String(row["model"]) : null,
  };
}

function fromTurnRow(row: Record<string, unknown>): TurnRecord {
  return {
    conversationId: String(row["conversation_id"]),
    turnIndex: Number(row["turn_index"]),
    role: String(row["role"]) as TurnRole,
    content: row["content"],
    model: row["model"] ? String(row["model"]) : null,
    tokensIn: Number(row["tokens_in"] ?? 0),
    tokensOut: Number(row["tokens_out"] ?? 0),
    costUsd: Number(row["cost_usd"] ?? 0),
    latencyMs: Number(row["latency_ms"] ?? 0),
    createdAt: toIso(row["created_at"]),
  };
}

function toIso(value: unknown): string {
  if (value instanceof Date) return value.toISOString();
  if (typeof value === "string") return new Date(value).toISOString();
  return new Date().toISOString();
}

import "reflect-metadata";
import { promises as fs } from "fs";
import path from "path";
import { DataSource } from "typeorm";
import { JobEntitySchema } from "./entities/JobEntity.js";
import { ModelTierAssignmentEntitySchema } from "./entities/ModelTierAssignmentEntity.js";
import { ObservabilityRequestEntitySchema } from "./entities/ObservabilityRequestEntity.js";
import { StepLifecycleEventEntitySchema } from "./entities/StepLifecycleEventEntity.js";
import { StepWorkItemEntitySchema } from "./entities/StepWorkItemEntity.js";
import { TickerWorkItemEntitySchema } from "./entities/TickerWorkItemEntity.js";
import { TrackedAssetEntitySchema } from "./entities/TrackedAssetEntity.js";
import { UserPointsBudgetEntitySchema } from "./entities/UserPointsBudgetEntity.js";
import { UserEntitySchema } from "./entities/UserEntity.js";
import { StrategyEntitySchema } from "./entities/StrategyEntity.js";
import { ReportBatchEntitySchema } from "./entities/ReportBatchEntity.js";
import { ReportIndexEntitySchema } from "./entities/ReportIndexEntity.js";
import { NotificationEntitySchema } from "./entities/NotificationEntity.js";
import { EscalationHistoryEntitySchema } from "./entities/EscalationHistoryEntity.js";
import { VerdictActionEntitySchema } from "./entities/VerdictActionEntity.js";
import { TickerSnoozeEntitySchema } from "./entities/TickerSnoozeEntity.js";
import { PortfolioRiskSnapshotEntitySchema } from "./entities/PortfolioRiskSnapshotEntity.js";
import { AdminAuditLogEntitySchema } from "./entities/AdminAuditLogEntity.js";
import { MigrationArchiveEntitySchema } from "./entities/MigrationArchiveEntity.js";
import { FeatureFlagEntitySchema } from "./entities/FeatureFlagEntity.js";
import { ChannelBindingEntitySchema } from "./entities/ChannelBindingEntity.js";
import { EncryptedSecretEntitySchema } from "./entities/EncryptedSecretEntity.js";
import { ConversationEntitySchema } from "./entities/ConversationEntity.js";
import { ConversationTurnEntitySchema } from "./entities/ConversationTurnEntity.js";
import { ToolCallEntitySchema } from "./entities/ToolCallEntity.js";
import { OutputFilterEventEntitySchema } from "./entities/OutputFilterEventEntity.js";
import { PositionTransactionEntitySchema } from "./entities/PositionTransactionEntity.js";
import { CorporateActionEntitySchema } from "./entities/CorporateActionEntity.js";
import { PilotFeatureReviewEntitySchema } from "./entities/PilotFeatureReviewEntity.js";
import { logger } from "../services/logger.js";

const APP_DATABASE_URL =
  process.env["APP_DATABASE_URL"] ??
  process.env["OBSERVABILITY_DATABASE_URL"] ??
  "";
const APP_DATABASE_DDL_PATH =
  process.env["APP_DATABASE_DDL_PATH"] ??
  process.env["OBSERVABILITY_DDL_PATH"] ??
  path.resolve(process.cwd(), "../db/application_postgres.sql");

let dataSource: DataSource | null = null;
let ddlApplied = false;

export function isApplicationDatabaseConfigured(): boolean {
  return APP_DATABASE_URL.length > 0;
}

function buildDataSource(): DataSource {
  if (!APP_DATABASE_URL) {
    throw new Error("APP_DATABASE_URL is required");
  }

  return new DataSource({
    type: "postgres",
    url: APP_DATABASE_URL,
    entities: [
      JobEntitySchema,
      ModelTierAssignmentEntitySchema,
      ObservabilityRequestEntitySchema,
      StepLifecycleEventEntitySchema,
      StepWorkItemEntitySchema,
      TickerWorkItemEntitySchema,
      TrackedAssetEntitySchema,
      UserPointsBudgetEntitySchema,
      // Phase 1 (design.md §4.1–4.17):
      UserEntitySchema,
      StrategyEntitySchema,
      ReportBatchEntitySchema,
      ReportIndexEntitySchema,
      NotificationEntitySchema,
      EscalationHistoryEntitySchema,
      VerdictActionEntitySchema,
      TickerSnoozeEntitySchema,
      PortfolioRiskSnapshotEntitySchema,
      AdminAuditLogEntitySchema,
      MigrationArchiveEntitySchema,
      FeatureFlagEntitySchema,
      ChannelBindingEntitySchema,
      EncryptedSecretEntitySchema,
      // Phase 5 (design.md §4.11–4.12):
      ConversationEntitySchema,
      ConversationTurnEntitySchema,
      ToolCallEntitySchema,
      OutputFilterEventEntitySchema,
      // Phase 7 (design.md §4.6–4.7):
      PositionTransactionEntitySchema,
      CorporateActionEntitySchema,
      // Pilot admin review state:
      PilotFeatureReviewEntitySchema,
    ],
    synchronize: false,
    logging: false,
  });
}

async function applyDdl(ds: DataSource): Promise<void> {
  if (ddlApplied) return;
  const ddl = await fs.readFile(APP_DATABASE_DDL_PATH, "utf-8");
  await ds.query(ddl);
  ddlApplied = true;
}

export async function getApplicationDataSource(): Promise<DataSource> {
  if (!dataSource) {
    dataSource = buildDataSource();
  }

  if (!dataSource.isInitialized) {
    await dataSource.initialize();
    await applyDdl(dataSource);
    logger.info("Application PostgreSQL data source initialized");
  }

  return dataSource;
}

export async function closeApplicationDataSource(): Promise<void> {
  if (dataSource?.isInitialized) {
    await dataSource.destroy();
  }
  dataSource = null;
  ddlApplied = false;
}

/**
 * TypeORM UPDATE/DELETE RETURNING result unwrapper.
 *
 * TypeORM 0.3.x wraps UPDATE/DELETE results as `[rows, rowCount]` while
 * SELECT/INSERT results are returned as `rows[]` directly. This helper
 * normalises both shapes so callers can always treat the result as `T[]`.
 *
 * See: TypeORM PostgresQueryRunner.js — case "UPDATE": result.raw = [raw.rows, raw.rowCount]
 */
export function unwrapMutationRows<T extends Record<string, unknown>>(result: unknown): T[] {
  if (!Array.isArray(result)) return [];
  // TypeORM UPDATE/DELETE shape: [[row, row, ...], rowCount]
  if (result.length === 2 && Array.isArray(result[0]) && typeof result[1] === "number") {
    return (result[0] as T[]).filter((r): r is T => r !== null && r !== undefined);
  }
  // INSERT RETURNING / SELECT shape: [row, row, ...]
  return (result as T[]).filter((r): r is T => r !== null && r !== undefined);
}

#!/usr/bin/env node
import { readdir } from "node:fs/promises";
import path from "node:path";
import { spawn } from "node:child_process";

const backendRoot = path.resolve(import.meta.dirname, "..");
const srcRoot = path.join(backendRoot, "src");

async function findTestFiles(dir) {
  const dirents = await readdir(dir, { withFileTypes: true });
  const files = await Promise.all(dirents.map(async (dirent) => {
    const fullPath = path.join(dir, dirent.name);
    if (dirent.isDirectory()) return findTestFiles(fullPath);
    return dirent.isFile() && dirent.name.endsWith(".test.ts") ? [fullPath] : [];
  }));
  return files.flat().sort((a, b) => a.localeCompare(b));
}

const testFiles = await findTestFiles(srcRoot);
const forwardedNodeTestArgs = process.argv.slice(2);
const child = spawn(
  process.execPath,
  ["--test", "--import", "tsx", ...forwardedNodeTestArgs, ...testFiles],
  { cwd: backendRoot, stdio: "inherit" }
);

child.on("exit", (code, signal) => {
  if (signal) {
    process.kill(process.pid, signal);
    return;
  }
  process.exit(code ?? 1);
});

import test from "node:test";
import assert from "node:assert/strict";

import type { PilotFeatureCatalogEntry } from "../schemas/pilotFeature.js";
import {
  PilotFeatureReviewServiceError,
  listPilotFeaturesWithReviews,
  upsertPilotFeatureReview,
  pilotFeatureReviewServiceInternals,
} from "./pilotFeatureReviewService.js";

const catalog: PilotFeatureCatalogEntry[] = [
  {
    id: "web.portfolio",
    surface: "web",
    title: "Portfolio overview",
    shortSummary: "Shows portfolio status.",
    detailedExplanation: "Shows portfolio holdings, health, and active analysis status for the pilot.",
    happyPath: ["User opens portfolio"],
    edgeCases: ["Empty portfolio renders an empty state"],
    errorHandling: ["API failure renders retryable error state"],
    evidencePaths: ["frontend/src/pages/Portfolio.tsx"],
    pilotRecommendation: "pilot",
  },
  {
    id: "telegram.daily-brief",
    surface: "telegram",
    title: "Daily brief delivery",
    shortSummary: "Sends daily summaries.",
    detailedExplanation: "Sends pilot daily brief summaries through the Telegram channel.",
    happyPath: ["Scheduler triggers daily brief"],
    edgeCases: ["Telegram chat is not linked"],
    errorHandling: ["Delivery failure is logged and retried by job lifecycle"],
    evidencePaths: ["backend/src/routes/telegram.ts"],
    pilotRecommendation: "pilot",
  },
];

interface QueryCall {
  sql: string;
  params: unknown[];
}

function makeDataSource(rowsByCall: unknown[][] = []) {
  const calls: QueryCall[] = [];
  return {
    calls,
    ds: {
      async query<T = unknown>(sql: string, params: unknown[]): Promise<T> {
        calls.push({ sql, params });
        return (rowsByCall.shift() ?? []) as T;
      },
    },
  };
}

function configuredDeps(ds: { query<T = unknown>(sql: string, params: unknown[]): Promise<T> }) {
  return {
    catalogLoader: async () => catalog,
    databaseConfigured: () => true,
    dataSourceProvider: async () => ds,
  };
}

function assertFeatureWithReviewContract(feature: Awaited<ReturnType<typeof listPilotFeaturesWithReviews>>[number]): void {
  assert.equal(typeof feature.id, "string");
  assert.ok(["admin", "operator", "telegram", "web"].includes(feature.surface));
  assert.equal(typeof feature.title, "string");
  assert.equal(typeof feature.shortSummary, "string");
  assert.equal(typeof feature.detailedExplanation, "string");
  assert.ok(Array.isArray(feature.happyPath) && feature.happyPath.length > 0);
  assert.ok(Array.isArray(feature.edgeCases) && feature.edgeCases.length > 0);
  assert.ok(Array.isArray(feature.errorHandling) && feature.errorHandling.length > 0);
  assert.ok(Array.isArray(feature.evidencePaths) && feature.evidencePaths.length > 0);
  assert.ok(["pilot", "beta", "defer", "hide"].includes(feature.pilotRecommendation));
  assert.ok(["unreviewed", "needs_fix", "beta", "hidden", "ready"].includes(feature.review.status));
  assert.ok(typeof feature.review.incorrectDescription === "boolean");
  assert.ok(feature.review.adminComment === null || typeof feature.review.adminComment === "string");
  assert.ok(feature.review.updatedAt === null || typeof feature.review.updatedAt === "string");
  assert.ok(feature.review.updatedBy === null || typeof feature.review.updatedBy === "string");
}

test("pilot feature review service composes catalog entries with default and persisted review state", async () => {
  const { ds, calls } = makeDataSource([
    [
      {
        feature_id: "telegram.daily-brief",
        status: "beta",
        admin_comment: "Watch first pilot cohort before marking ready.",
        incorrect_description: false,
        updated_at: new Date("2026-01-02T03:04:05.000Z"),
        updated_by: "owner",
      },
    ],
  ]);

  const result = await listPilotFeaturesWithReviews(configuredDeps(ds));

  assert.equal(calls.length, 1);
  assert.match(calls[0]!.sql, /WHERE feature_id = ANY\(\$1::text\[\]\)/);
  assert.deepEqual(calls[0]!.params, [["web.portfolio", "telegram.daily-brief"]]);
  for (const feature of result) {
    assertFeatureWithReviewContract(feature);
  }
  assert.equal(result[0]!.review.status, "unreviewed");
  assert.equal(result[0]!.review.updatedAt, null);
  assert.equal(result[1]!.review.status, "beta");
  assert.equal(result[1]!.review.adminComment, "Watch first pilot cohort before marking ready.");
  assert.equal(result[1]!.review.updatedAt, "2026-01-02T03:04:05.000Z");
});

test("pilot feature review service upserts a known feature review", async () => {
  const updatedAt = new Date("2026-02-03T04:05:06.000Z");
  const { ds, calls } = makeDataSource([
    [
      {
        feature_id: "web.portfolio",
        status: "ready",
        admin_comment: "Good enough for pilot.",
        incorrect_description: true,
        updated_at: updatedAt,
        updated_by: "owner",
      },
    ],
  ]);

  const result = await upsertPilotFeatureReview(
    {
      featureId: " web.portfolio ",
      status: "ready",
      adminComment: "Good enough for pilot.",
      incorrectDescription: true,
      updatedBy: " owner ",
    },
    configuredDeps(ds)
  );

  assert.equal(calls.length, 1);
  assert.match(calls[0]!.sql, /ON CONFLICT \(feature_id\)/);
  assert.deepEqual(calls[0]!.params, [
    "web.portfolio",
    "ready",
    "Good enough for pilot.",
    true,
    "owner",
  ]);
  assert.equal(result.id, "web.portfolio");
  assertFeatureWithReviewContract(result);
  assert.deepEqual(result.review, {
    status: "ready",
    adminComment: "Good enough for pilot.",
    incorrectDescription: true,
    updatedAt: "2026-02-03T04:05:06.000Z",
    updatedBy: "owner",
  });
});

test("pilot feature review service rejects invalid status and oversized comments before writing", async () => {
  const { ds, calls } = makeDataSource();

  await assert.rejects(
    () => upsertPilotFeatureReview(
      {
        featureId: "web.portfolio",
        status: "launched",
        updatedBy: "owner",
      },
      configuredDeps(ds)
    ),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "INVALID_REVIEW_INPUT"
  );

  await assert.rejects(
    () => upsertPilotFeatureReview(
      {
        featureId: "web.portfolio",
        status: "ready",
        adminComment: "x".repeat(pilotFeatureReviewServiceInternals.MAX_ADMIN_COMMENT_LENGTH + 1),
        updatedBy: "owner",
      },
      configuredDeps(ds)
    ),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "INVALID_REVIEW_INPUT"
  );

  assert.equal(calls.length, 0);
});

test("pilot feature review service refuses unknown catalog ids before writing", async () => {
  const { ds, calls } = makeDataSource();

  await assert.rejects(
    () => upsertPilotFeatureReview(
      {
        featureId: "web.missing",
        status: "ready",
        updatedBy: "owner",
      },
      configuredDeps(ds)
    ),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "UNKNOWN_FEATURE_ID"
  );

  assert.equal(calls.length, 0);
});

test("pilot feature review service exposes unavailable database and catalog load failures as typed errors", async () => {
  const { ds, calls } = makeDataSource();

  await assert.rejects(
    () => listPilotFeaturesWithReviews({
      catalogLoader: async () => catalog,
      databaseConfigured: () => false,
      dataSourceProvider: async () => ds,
    }),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "DATABASE_UNAVAILABLE"
  );
  assert.equal(calls.length, 0);

  await assert.rejects(
    () => listPilotFeaturesWithReviews({
      catalogLoader: async () => { throw new Error("boom"); },
      databaseConfigured: () => true,
      dataSourceProvider: async () => ds,
    }),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "CATALOG_LOAD_FAILED"
  );
});

import test from "node:test";
import assert from "node:assert/strict";
import os from "node:os";
import path from "node:path";
import { promises as fs } from "node:fs";
import type { UserWorkspace } from "../middleware/userIsolation.js";

const testRoot = await fs.mkdtemp(path.join(os.tmpdir(), "job-state-reconciler-"));
const usersDir = path.join(testRoot, "users");
process.env["USERS_DIR"] = usersDir;

interface TestContext {
  ws: UserWorkspace;
  reconcilePausedJobStates: typeof import("./jobStateReconciler.js")["reconcilePausedJobStates"];
}

async function setup(userId: string): Promise<TestContext> {
  const [{ buildWorkspace }, mod] = await Promise.all([
    import("../middleware/userIsolation.js"),
    import("./jobStateReconciler.js"),
  ]);
  const ws = buildWorkspace(userId, usersDir);
  await fs.mkdir(ws.jobsDir, { recursive: true });
  await fs.mkdir(ws.reportsDir, { recursive: true });
  return { ws, reconcilePausedJobStates: mod.reconcilePausedJobStates };
}

async function writeJson(p: string, value: unknown): Promise<void> {
  await fs.mkdir(path.dirname(p), { recursive: true });
  await fs.writeFile(p, JSON.stringify(value, null, 2), "utf-8");
}

async function readJson<T>(p: string): Promise<T> {
  return JSON.parse(await fs.readFile(p, "utf-8")) as T;
}

test("returns 0 when user has no jobs", async () => {
  const { ws, reconcilePausedJobStates } = await setup("user-no-jobs");
  const repairs = await reconcilePausedJobStates(ws);
  assert.equal(repairs, 0);
});

test("returns 0 when full_report_state.json does not exist", async () => {
  const { ws, reconcilePausedJobStates } = await setup("user-no-state");
  await writeJson(ws.jobFile("job_test_1"), {
    id: "job_test_1",
    action: "full_report",
    ticker: null,
    status: "paused",
    triggered_at: "2026-04-26T07:09:56.648Z",
    started_at: null,
    completed_at: null,
    result: null,
    error: null,
  });
  const repairs = await reconcilePausedJobStates(ws);
  assert.equal(repairs, 0);
});

test("rewrites state.json from running to paused when matching paused job exists", async () => {
  const { ws, reconcilePausedJobStates } = await setup("user-divergent");
  const jobId = "job_20260426_144855_1abcd8";
  await writeJson(ws.jobFile(jobId), {
    id: jobId,
    action: "full_report",
    ticker: null,
    status: "paused",
    triggered_at: "2026-04-26T07:09:56.648Z",
    started_at: "2026-04-27T11:47:00.000Z",
    completed_at: "2026-04-27T11:53:00.000Z",
    result: null,
    error: "execution_constraints: Unable to run detailed market analysis",
  });
  const statePath = path.join(ws.reportsDir, "full_report_state.json");
  await writeJson(statePath, {
    version: 1,
    jobId,
    status: "running",
    currentTicker: "QQQ",
    currentStep: "Fundamentals",
    updatedAt: "2026-04-27T11:53:37.948Z",
  });

  const repairs = await reconcilePausedJobStates(ws);
  assert.equal(repairs, 1);

  const state = await readJson<{ status: string; updatedAt: string }>(statePath);
  assert.equal(state.status, "paused");
  assert.notEqual(state.updatedAt, "2026-04-27T11:53:37.948Z"); // bumped
});

test("is idempotent: second call repairs nothing", async () => {
  const { ws, reconcilePausedJobStates } = await setup("user-idempotent");
  const jobId = "job_idem";
  await writeJson(ws.jobFile(jobId), {
    id: jobId,
    action: "full_report",
    ticker: null,
    status: "paused",
    triggered_at: "2026-04-26T07:09:56.648Z",
    started_at: null,
    completed_at: null,
    result: null,
    error: null,
  });
  const statePath = path.join(ws.reportsDir, "full_report_state.json");
  await writeJson(statePath, { version: 1, jobId, status: "running", updatedAt: "2026-04-27T00:00:00.000Z" });

  assert.equal(await reconcilePausedJobStates(ws), 1);
  assert.equal(await reconcilePausedJobStates(ws), 0);
});

test("does not touch state.json belonging to a different jobId", async () => {
  const { ws, reconcilePausedJobStates } = await setup("user-mismatched-job");
  await writeJson(ws.jobFile("job_old_paused"), {
    id: "job_old_paused",
    action: "full_report",
    ticker: null,
    status: "paused",
    triggered_at: "2026-04-20T00:00:00.000Z",
    started_at: null,
    completed_at: null,
    result: null,
    error: null,
  });
  const statePath = path.join(ws.reportsDir, "full_report_state.json");
  await writeJson(statePath, {
    version: 1,
    jobId: "job_currently_running",
    status: "running",
    updatedAt: "2026-04-30T10:00:00.000Z",
  });

  const repairs = await reconcilePausedJobStates(ws);
  assert.equal(repairs, 0);
  const state = await readJson<{ status: string }>(statePath);
  assert.equal(state.status, "running");
});

test("repairs state.json regardless of whether status is paused, failed, cancelled, or superseded", async () => {
  for (const terminalStatus of ["paused", "failed", "cancelled", "superseded"] as const) {
    const { ws, reconcilePausedJobStates } = await setup(`user-${terminalStatus}`);
    const jobId = `job_${terminalStatus}`;
    await writeJson(ws.jobFile(jobId), {
      id: jobId,
      action: "full_report",
      ticker: null,
      status: terminalStatus,
      triggered_at: "2026-04-26T00:00:00.000Z",
      started_at: null,
      completed_at: null,
      result: null,
      error: null,
    });
    const statePath = path.join(ws.reportsDir, "full_report_state.json");
    await writeJson(statePath, { version: 1, jobId, status: "running", updatedAt: "2026-04-27T00:00:00.000Z" });

    assert.equal(await reconcilePausedJobStates(ws), 1, `should repair when job status=${terminalStatus}`);
    const state = await readJson<{ status: string }>(statePath);
    assert.equal(state.status, terminalStatus);
  }
});

